import { RefProxy, ReadonlyRefProxy } from "@hoge1e3/ref";
import { PathRef } from "./immer-path-ref.js";
export type PathRefProxy<T> = {
    __unproxy__: PathRef<T>;
} & {
    [K in keyof T]: PathRefProxy<T[K]>;
} & RefProxy<T>;
export type ReadonlyPathRefProxy<T> = {
    __unproxy__: PathRef<T>;
} & {
    [K in keyof T]: PathRefProxy<T[K]>;
} & ReadonlyRefProxy<T>;
export declare function f<T, N>(p: ReadonlyPathRefProxy<T>, m: (o: T) => N): ReadonlyPathRefProxy<N>;
export declare function create<T>(val: T): PathRefProxy<T>;
